sql:
SELECT first_name, last_name, age
FROM customers
WHERE account_id IN (
    SELECT account_id
    FROM purchases
);

SELECT email 
FROM customers 
WHERE account_id = '0';

SELECT DISTINCT account_id
FROM purchases
WHERE purchase_date BETWEEN '2023-01-01' AND '2023-01-31';

external_knowledge:
- "navigators" refers to customers receiving discounts;
- "ships" refers to customer accounts;
- "savings waves" refers to discount percentages;
- "loyalty point mountains" refers to point balances;
- "common waves" refers to average discount percentages;
- "average tides" refer to average point balances.

sql:
SELECT COUNT(DISTINCT customers.account_id) 
FROM customers
JOIN customer_feedback ON customers.account_id = customer_feedback.account_id;

SELECT COUNT(DISTINCT p.account_id) AS number_of_customers
FROM purchases p
WHERE p.total_amount > 100.00;

SELECT DISTINCT c.account_id, c.first_name, c.last_name
FROM customers c
JOIN discounts d ON c.account_id = d.account_id;

SELECT COUNT(DISTINCT account_id) AS total_customers
FROM campaign_responses
WHERE campaign_id = 1 AND response_type = 'purchase';
